import{_ as a,c as i,a as e,b as s,o as l}from"./app-CEcM0piI.js";const p={};function d(c,n){return l(),i("div",null,n[0]||(n[0]=[e(`<p>esmodule导入包时需要是<code>/</code>、<code>./</code>、<code>../</code>开头的，虽然走的流程依旧是查找node_modules文件夹下的模块，但却没有做自动检索node_modules的功能是因为es中导入操作是通过网络请求的，如果做了自动查找功能，那么浏览器在加载时就需要通过网络请求去node_modules检索第三方库，而且第三方库还可能导入了其他库因此会又循环检索依赖的问题，就会发送很多网络请求 而commonjs规范可以做自动检索node_modules功能的原因是nodejs是运行在服务端，它检索时不依靠网络请求，而是在本地磁盘检索</p><p>而使用vite打包项目vite是提供了自动检索node_modules的功能，他会自动进行处理</p><p>vite在处理的过程中如果看到的了有非相对或绝对路径的引用就会开启路径补全：<code>/node_modules/.vite/原路径</code> 找寻路径的过程是从当前目录开始依次向上查找，直到根目录或者找到对应的依赖项</p><p>vite是在node中运行的，可以使用es规范是因为vite在读取配置时会检测是es规范还是commonjs规范，如果是es规范会转成commonjs规范</p><h3 id="开发和生产环境" tabindex="-1"><a class="header-anchor" href="#开发和生产环境"><span>开发和生产环境</span></a></h3><h4 id="开发环境" tabindex="-1"><a class="header-anchor" href="#开发环境"><span>开发环境</span></a></h4><p>每次依赖预构建所重新构建的相对路径都是正确的</p><p>许多依赖使用的规范是不同的，vite无法约束库的作者都使用同一种规范 首先vite会找到对应的依赖，然后调用esbuild（对js语法进行处理的一个库），将其他规范的代码转换成esmodule规范，然后放到当前目录下的<code>node_modules/.vite/deps</code> 他解决了3个问题：</p><ol><li>不同的第三方包会有不同的导出格式（这个是vite没法约束人家的事情）</li><li>对路径的处理上可以直接使用.vite/deps，方便路径重写</li><li>叫做网络多包传输的性能问题（也是原生esmodule规范不敢支持node_modules的原因之一） vite在检测到导入导出包时会把引入的内容植入到当前文件，这样浏览器就检测不到要导包的操作了也就不需要处理了</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default function a(){}</span></span>
<span class="line"><span>export {default as a} from &#39;./a.js&#39;</span></span>
<span class="line"><span>//vite重写为</span></span>
<span class="line"><span>function a(){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="生产环境" tabindex="-1"><a class="header-anchor" href="#生产环境"><span>生产环境</span></a></h4><p>vite会全权交给一个叫做rollup的库去完成生产环境的打包</p><h1 id="配置" tabindex="-1"><a class="header-anchor" href="#配置"><span>配置</span></a></h1><p>不同环境下配置 将开发环境配置和生产环境配置放在不同的文件中，检测构建的命令来区别加载不同的配置</p><div class="language-vite.config.js line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="vite.config.js" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import {defineConfig} from &#39;vite&#39;</span></span>
<span class="line"><span>import viteBaseConfig form &#39;./vite.bace.config.js&#39;</span></span>
<span class="line"><span>import viteDevConfig form &#39;./vite.development.config.js&#39;</span></span>
<span class="line"><span>import viteProConfig form &#39;./vite.production.config.js&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const envResolver={</span></span>
<span class="line"><span>	&quot;build&quot;:()=&gt;{</span></span>
<span class="line"><span>		console.log(&#39;生产环境&#39;)</span></span>
<span class="line"><span>		return ({...viteBaseConfig,...viteProConfig})</span></span>
<span class="line"><span>	},</span></span>
<span class="line"><span>	&quot;serve&quot;:()=&gt;{</span></span>
<span class="line"><span>		console.log(&#39;开发环境&#39;)</span></span>
<span class="line"><span>		return ({...viteBaseConfig,...viteProConfig})</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export default defineConfig((command:&#39;build&#39;|&#39;server&#39;)=&gt;{</span></span>
<span class="line"><span>	retrun envResolver[command]()</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>使用函数接收defineConfig传入的参数，command是根据npm（或yarn、pnpm）等脚本命令获取的</p><ul><li>optimizeDeps：依赖预处理 <ul><li>exclude：排除的包，被排除的包将不会被vite进行依赖预处理而是直接使用默认方式</li></ul></li></ul><h2 id="环境变量" tabindex="-1"><a class="header-anchor" href="#环境变量"><span>环境变量</span></a></h2><p>vite内置了dotenv库，如果根目录有.env时会读取.env文件中的内容并注入到process中</p><p>也可以手动调用loadEnv函数加载不同的环境变量</p><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default defineConfig((command:&#39;build&#39;|&#39;server&#39;,mode:string)=&gt;{</span></span>
<span class="line"><span>	loadEnv(mode,process.cwd,&#39;&#39;)</span></span>
<span class="line"><span>	retrun envResolver[command]()</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>mode是defineConfig传入的一个参数，代表当前所处环境 手动调用loadEnv时，会先加载<code>.env</code>文件，其次会根据传入的mode的值进行拼接，格式为：<code>.env.[mode]</code>并根据第二个参数中提供的路径去查找该文件，如果有关于mode的配置文件那么最后得到的环境变量内容就是两个环境变量配置文件中的内容的并集</p><p><strong>但是在浏览器中直接运行的js代码中却无法获取到环境变量配置文件中的环境变量</strong> vite做了一个拦截，他为了防止我们将隐私性的变量直接送进<code>import.meta.env</code>中，所以他做了一层拦截，如果环境变量不是以<code>VITE</code>开头的，他就不会注入到客户端中去</p><p>解决方法：</p><ol><li>将环境变量命名以<code>VITE</code>开头</li><li>在<code>vite.config.js</code>中配置<code>envPrefix</code>。自行设置以什么开头</li></ol><h2 id="内容解析" tabindex="-1"><a class="header-anchor" href="#内容解析"><span>内容解析</span></a></h2><h3 id="css" tabindex="-1"><a class="header-anchor" href="#css"><span>css</span></a></h3><ol><li>vite在读取到main.js中引用到了Index.csS</li><li>直接去使用fs模块去读取index.Css中文件内容</li><li>直接创建一个style标签，将index.css中文件内容直接copy进style标签里</li><li>将style标签插入到index.html的head中</li><li>将该css文件中的内容直接替换为js脚本（方便热更新或者css模块化），同时设置Content-Type为js从而让浏览器以JS脚本的形式来执行该css后缀的文件</li></ol><h4 id="样式冲突" tabindex="-1"><a class="header-anchor" href="#样式冲突"><span>样式冲突</span></a></h4><p>要解决样式冲突需要使用css module，给要用到的css文件命名为<code>文件名.module.css</code>，这样在导入css样式后的css属性命名就会是<code>属性名_哈希值</code>的形式。且在使用时也不能像以前一样直接以字符串形式设置css属性 因为属性名已经是加上哈希值的形式了，所以只能像操作对象的方法添加css属性</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import componentACss from &#39;./componentA.module.css&#39;</span></span>
<span class="line"><span>let div=document.createElement(&#39;div&#39;)</span></span>
<span class="line"><span>// div.classList.add(&#39;footer&#39;)不适用了</span></span>
<span class="line"><span>div.className=componentACss.footer</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>vite也支持less进行处理，操作方法和css一样，需要安装less预处理器</p><h4 id="原理" tabindex="-1"><a class="header-anchor" href="#原理"><span>原理</span></a></h4>`,33),s("ol",null,[s("li",null,"module.css（module是一种约定，表示需要开启css模块化）"),s("li",null,"他会将你的所有类名进行一定规则的替换（将footer替换成_footer_i22st_1）"),s("li",{"footer:_footer_i22st_1":""},"同时创建一个映射对象"),s("li",null,"将替换过后的内容塞进style标签里然后放入到head标签中（能够读到index.html的文件内容）"),s("li",null,"将componentA.module.css内容进行全部抹除，替换成JS脚本"),s("li",null,"将创建的映射对象在脚本中进行默认导出")],-1),e(`<h4 id="配置-1" tabindex="-1"><a class="header-anchor" href="#配置-1"><span>配置</span></a></h4><p>对于css处理行为也可以在vite配置文件中进行配置</p><div class="language-vite.config.js line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="vite.config.js" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>css:{</span></span>
<span class="line"><span>	modules:{    //对css模块化的默认行为进行配置</span></span>
<span class="line"><span>		localsConvention:&quot;camelCase&quot;,    //对处理生成的css属性类名配置驼峰命名</span></span>
<span class="line"><span>		scopeBehaviour:&quot;local&quot;,    //配置当前模块化行为是局部还是全局（表示的是css属性是作用于全局还是局部，如果是局部则会进行模块化，全局表示css属性应用在全局不开启模块化）</span></span>
<span class="line"><span>		generateScopedName:&quot;[name]_[local]_[hash:5]&quot;,    //生成的css属性名规则，也可以是函数形式，如果是函数形式，那么生成的命名规则根据返回值决定</span></span>
<span class="line"><span>		generateScopedName:(name,filename,css)=&gt;{</span></span>
<span class="line"><span>		// name-&gt; 代表此刻css文件中的类名</span></span>
<span class="line"><span>		// filename-&gt; 当前css文件的绝对路径</span></span>
<span class="line"><span>		// css-&gt; 当前样式</span></span>
<span class="line"><span>			return \`\${name}_\${filename}_{css}\`</span></span>
<span class="line"><span>		},</span></span>
<span class="line"><span>		hashPrefix:&quot;hello&quot;,    //配置生成哈希前的字符串，配置的字符串将参与css属性类名哈希值的生成，可以使生成的哈希值出现哈希碰撞的概率更小</span></span>
<span class="line"><span>		globalModulePath:[&#39;./assets/css/component&#39;]    //表示不参与模块化生成css的路径</span></span>
<span class="line"><span>	},</span></span>
<span class="line"><span>	preprocessorOptions:{    //css（样式）系列的预处理配置（包括less，sass等）</span></span>
<span class="line"><span>		less:{    //配置less命令将less文件处理成css时的命令行参数</span></span>
<span class="line"><span>			math:&quot;always&quot;,     //表示是否总是启用数学表达式，如果是always那么less中的数学表达式都会被运算，如果不启用less中只有在小括号内的数学表达式才被运算</span></span>
<span class="line"><span>			globalVars:{    //全局变量</span></span>
<span class="line"><span>				mainColor:&quot;red&quot;,    //配置全局变量mainColor颜色为红色，这样所有的less文件使用时都不需要导入了（导入会有些性能影响）</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		},</span></span>
<span class="line"><span>		devSourcemap:true,    //开启源码映射</span></span>
<span class="line"><span>		postcss:{    //配置postcss</span></span>
<span class="line"><span>		</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>也可以不配置postcss，如果在项目根目录下有<code>postcss.config.js</code>文件的话即使不在vite中配置，vite也会自动找到并读取其中的配置 如果在vite中配置了postcss，那么它的优先级是比<code>postcss.config.js</code>文件高的</p><h2 id="加载静态资源" tabindex="-1"><a class="header-anchor" href="#加载静态资源"><span>加载静态资源</span></a></h2><p>json配置也是静态资源 在其他的打包工具中json会被当做json字符串的形式存在，而vite是一个json对象</p><p><strong>摇树优化</strong> 在导入库时如果把整个库当作一个对象引入，打包工具就不会启用摇树优化。因为它无法判断一个对象中的属性以后是否会用到。 如果使用按需导入，那么在打包时打包工具会启用摇树优化将不需要的对象或函数祛除。 对于json对象也是，如果有些json中的配置没有用到，那么打包的时候就不会把没用到的内容引入，而是被摇树优化祛除</p><h3 id="路径别名" tabindex="-1"><a class="header-anchor" href="#路径别名"><span>路径别名</span></a></h3><p>在项目中使用<code>@</code>代表项目根目录就是在vite中配置的，是借助rollup的alias插件实现的</p><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>resolve:{</span></span>
<span class="line"><span>	alias:{</span></span>
<span class="line"><span>		&quot;@&quot;:path.resolve(_dirname,&#39;./src&#39;)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>[!NOTE] 为什么要有哈希 浏览器是由缓存机制的，只要文件名不改那么浏览器就会默认去缓存读取，每次修改都更改文件名后的哈希值这样可以保证数据准确性</p></blockquote><h2 id="构建配置" tabindex="-1"><a class="header-anchor" href="#构建配置"><span>构建配置</span></a></h2><h3 id="rollup" tabindex="-1"><a class="header-anchor" href="#rollup"><span>rollup</span></a></h3><p>vite在构建到线上环境时由于线上环境兼容性的复杂，它是交给rollup处理的 用于配置静态资源</p><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>build:{    //构建配置</span></span>
<span class="line"><span>	rollupOptions:{    //配置rollup</span></span>
<span class="line"><span>		output:{    //控制输出</span></span>
<span class="line"><span>			assetFileNames:&quot;[hash]_[name]_[ext]&quot;    //静态资源命名规则</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	},</span></span>
<span class="line"><span>	assetsInlineLimit:4096000    //配置转换成base64编码的最大静态资源体积，如果超过该限制则不会转换成base64</span></span>
<span class="line"><span>	outDir:&quot;dist&quot;,    //构建输出文件夹名</span></span>
<span class="line"><span>	assetsDir:&quot;assets&quot;,    //静态文件输出所在文件夹名，在outDir内，默认是assets</span></span>
<span class="line"><span>	emptyOutDir:true,    //每次构建时是否清空输出目录</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="插件" tabindex="-1"><a class="header-anchor" href="#插件"><span>插件</span></a></h1><p>插件的配置是在<code>plugins</code>数组属性中针对所安装的插件进行配置 在使用时插件具有默认配置，但不再配置中创建出来插件的对象也是不会生效的</p><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>plugins:[</span></span>
<span class="line"><span>	ViteAliases()</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>vite相比于webpack有很多功能不需要配置就可以使用，这是因为vite内置了很多插件</p><h2 id="常用插件" tabindex="-1"><a class="header-anchor" href="#常用插件"><span>常用插件</span></a></h2><h3 id="vite-aliases" tabindex="-1"><a class="header-anchor" href="#vite-aliases"><span>vite-aliases</span></a></h3><p>vite-aliases可以帮助我们自动生成别名：检测你当前目录下包括src在内的所有文件夹，并帮助我们去生成别名</p><h3 id="vite-plugin-html" tabindex="-1"><a class="header-anchor" href="#vite-plugin-html"><span>vite-plugin-html</span></a></h3><p>能够动态地改变标签页的title</p><p>使用的是ejs语法 ejs在服务端会用的比较频繁因为服务端可能经常会动态的去修改index.html的内容</p><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>plugins:[</span></span>
<span class="line"><span>	createHtmlPlugin({</span></span>
<span class="line"><span>		inject:{</span></span>
<span class="line"><span>			data:{</span></span>
<span class="line"><span>				title:&quot;首页&quot;</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	})</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在html中使用时用ejs语法取出data中配置的数据</p><div class="language-index.html line-numbers-mode" data-highlighter="shiki" data-ext="index.html" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;%= title %&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="vite-plugin-mock" tabindex="-1"><a class="header-anchor" href="#vite-plugin-mock"><span>vite-plugin-mock</span></a></h3><p>不需要太多配置，直接在vite配置的<code>plugins</code>列表中创建出来即可 是依赖于mock.js的，做模拟数据用（类似于json-server但更高级些） mock.js安装后每次启动项目会默认扫描项目根目录下的src下的mock文件夹中的js文件，其其中的js文件是使用mock.js规范模拟的网络接口形式启动的网络服务</p><h3 id="vite-plugin-checker" tabindex="-1"><a class="header-anchor" href="#vite-plugin-checker"><span>vite-plugin-checker</span></a></h3><p>错误检查插件，ts在检查到语法不符合ts规范但符合js规范时虽然也会报错但并不会阻止编译，使用<code>vite-plugin-checker</code>插件并开启检查后就需要强制解决ts报错才会进行编译</p><p><strong>tsc编译</strong></p><ul><li>noEmit：当编译ts出错时直接退出编译并报错。如果不使用这个参数，当ts编译出错后并不会停止编译，而是要等vite构建时发现报错才会退出</li></ul><div class="language-package.json line-numbers-mode" data-highlighter="shiki" data-ext="package.json" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&quot;scripts&quot;:[</span></span>
<span class="line"><span>	&quot;build&quot;:&quot;tsc -noEmit &amp;&amp; vite build&quot;</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="生命周期" tabindex="-1"><a class="header-anchor" href="#生命周期"><span>生命周期</span></a></h2><p>vite会在生命周期的不同阶段中去调用不同的插件以达到不同的目的</p><p>vite在开发环境下使用的是自己的一套方案，在生产环境下使用的是rollup rollup有一些自己的生命周期函数，vite对于这些生命周期函数也起了同名的生命周期函数，这样就有了一些双方通用的生命周期 除了rollup的生命周期函数，vite也多了自己所独有的生命周期钩子</p><p>vite会在特定的生命周期去读取<code>vite.config.js</code>中的<code>plugins</code>数组属性，从中读取符合生命周期的插件并执行</p><p>也就是说vite配置中的<code>plugins</code>数组属性接收的是一个对象类型 但很多插件都是以函数的方式返回的，这是因为对函数传入不同的参数可以定制化自己需要的插件配置</p><p>不同的插件可能调用了相同的生命周期，对于这些许多插件的生命周期函数执行顺序也有不同，可以使用<code>enforce</code>属性配置执行顺序</p><h3 id="config" tabindex="-1"><a class="header-anchor" href="#config"><span>config</span></a></h3><p>config是vite特有的一个生命周期，它在vite读取配置文件前执行</p><p>自制的vite插件需要返回的是一个<strong>包含了</strong>vite中的<code>config</code>对象</p><p>这个对象是部分的<code>viteConfig</code>配置，也就是自己的插件需要修改的<code>viteConfig</code>的部分</p><ul><li>config：自己在<code>vite.config.js</code>中创建的配置对象会原封不动的以该参数的名字传过来</li><li>env：</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>config(config,env,){</span></span>
<span class="line"><span>	return {</span></span>
<span class="line"><span>		envPrefix:&quot;abc&quot;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="transformindexhtml" tabindex="-1"><a class="header-anchor" href="#transformindexhtml"><span>transformIndexHtml</span></a></h3><p>转化为html时调用</p><ul><li>html：读取到的html</li><li>ctx：整个请求的执行器上下文</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>module.exports=(options)=&gt;{</span></span>
<span class="line"><span>	return {</span></span>
<span class="line"><span>		transformIndexHtml(html,ctx){</span></span>
<span class="line"><span>			return</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="configureserver" tabindex="-1"><a class="header-anchor" href="#configureserver"><span>configureServer</span></a></h3><p>服务器相关配置 传入参数是上一个服务器相关信息对象</p><ul><li>req：请求对象：用户发来的请求</li><li>res：响应对象</li><li>next：是否交给下一个中间件处理，是一个函数类型。如果不交给下一个中间件处理不需要管，如果要交给下一个中间件处理就手动调用<code>next()</code></li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default (options)=&gt;{</span></span>
<span class="line"><span>	return {</span></span>
<span class="line"><span>		configureServer(server){</span></span>
<span class="line"><span>			server.middlewares.use(req,res,next)=&gt;{</span></span>
<span class="line"><span>				next();</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="自制插件" tabindex="-1"><a class="header-anchor" href="#自制插件"><span>自制插件</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export defalut function{</span></span>
<span class="line"><span>	return {</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>[!Warning] Title 通过<code>vite.config.js</code>中配置的对象和插件中返回的对象都不是被vite最终读取的对象 而它们最终会被合并成一个对象供vite读取</p></blockquote><h1 id="优化" tabindex="-1"><a class="header-anchor" href="#优化"><span>优化</span></a></h1><h2 id="开发时态的构建速度优化" tabindex="-1"><a class="header-anchor" href="#开发时态的构建速度优化"><span>开发时态的构建速度优化</span></a></h2><ul><li>webpack在这方面下的功夫是很重：cache-loadercacheloader结果（如果两次构建源代码没有产生变化，则直接使用缓存不调用loader），thread-loader，开启多线程去构建....</li><li>vite是按需加载，所以我们不需要太care这方面</li></ul><h2 id="页面性能指标" tabindex="-1"><a class="header-anchor" href="#页面性能指标"><span>页面性能指标</span></a></h2><h3 id="首屏渲染时" tabindex="-1"><a class="header-anchor" href="#首屏渲染时"><span>首屏渲染时</span></a></h3><p>fcp（first content paint），（first content paint-&gt;页面中第一个元素的渲染时长）</p><ul><li>懒加载：需要我们去写代码实现的</li><li>http优化：协商缓存和强缓存</li><li>强缓存：服务端给响应头追加一些字段（expires），客户端会记住这些字段，在expires（截止失效时间）没有到达之前，无论你怎么刷新页面，浏览器都不会重新请求页面，而是从缓存里取</li><li>协商缓存：是否使用缓存要跟后端商量一下，当服务端给我们打上协商缓存的标记以后，客户端在下次刷新页面需要重新请求资源时会发送一个协商请求给到服务端，服务端如果说需要变化则会响应具体的内容，如果服务端觉得没变化则会响应304</li></ul><h3 id="页面中最大元素的一个时长" tabindex="-1"><a class="header-anchor" href="#页面中最大元素的一个时长"><span>页面中最大元素的一个时长</span></a></h3><p>lcp（largest content paint)</p><h2 id="js逻辑" tabindex="-1"><a class="header-anchor" href="#js逻辑"><span>js逻辑</span></a></h2><ul><li>副作用的清除：组件是会频繁的挂载和卸载：如果我们在某一个组件中有计时器（setTimeout），如果我们在卸载的时候不去清除这个计时器，下次再次挂载的时候计时器等于开了两个线程</li><li>在必要时卡浏览器帧率：requestAnimationFrame、requestIdleCallback对浏览器渲染原理要有一定的认识然后再这方面做优化 requestIdleCallback：传一个函数进去 浏览器的帧率：16.6ms去更新一次（执行js逻辑、重排重绘）假设某个js执行逻辑超过了16.6ms就会发生掉顿，因此在必要时可以卡浏览器帧率让它帧率和该js逻辑同步避免掉帧</li></ul><h2 id="css-1" tabindex="-1"><a class="header-anchor" href="#css-1"><span>CSS</span></a></h2><ul><li>关注继承属性：能继承的旧不要重复写</li><li>尽量避免太过于深的css嵌套</li></ul><h2 id="构建优化" tabindex="-1"><a class="header-anchor" href="#构建优化"><span>构建优化</span></a></h2><p>vite（rollup）webpack</p><ul><li>优化体积：压缩，treeshaking，图片资源压缩，cdn加载，分包 只有构建优化是使用构建工具要考虑的优化</li></ul><h3 id="分包" tabindex="-1"><a class="header-anchor" href="#分包"><span>分包</span></a></h3><p>当项目文件导入不经常更改的包（如第三方库等）时，默认打包是将导入的包和当前文件打到一个文件中，这样就导致文件体积变得很大，但如果项目文件的逻辑进行更改而导入的包没有更改那么又要重新生成大体积的文件，浏览器就要重新请求。因为一小部分的更改而请求巨大的包，所付出的性能代价也需要优化</p><p>在vite中配置分包策略</p><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&quot;build&quot;:{</span></span>
<span class="line"><span>	&quot;minify&quot;:false,</span></span>
<span class="line"><span>	&quot;rollupOptions&quot;:{</span></span>
<span class="line"><span>		&quot;output&quot;:{</span></span>
<span class="line"><span>			&quot;manualChunks&quot;:(id)=&gt;{</span></span>
<span class="line"><span>				if(id.includes(&quot;node_modules&quot;)){    //包的路径是否包含node_modules</span></span>
<span class="line"><span>					return &quot;vendor&quot;    //返回vendor命名，将符合条件的包打入这个命名的文件中</span></span>
<span class="line"><span>				}</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>当多个文件引入同一个包时</strong> 在旧版的vite中，当多个文件引入同一个包构建时并不会有任何优化，每个文件中都有一份该包的拷贝，需要自己手动配置来解决 vite4版本直接导入内置插件splitVendorChunkPlugin，不需要任何配置了。</p><h3 id="gzip压缩" tabindex="-1"><a class="header-anchor" href="#gzip压缩"><span>gzip压缩</span></a></h3><p>将资源使用gzip压缩后传输给服务器减少网络传输的体积 浏览器接收到gzip压缩包后解压缩</p><p>在vite中<code>vite-plugin-compression</code>插件用于gizp打包</p><h3 id="动态导入" tabindex="-1"><a class="header-anchor" href="#动态导入"><span>动态导入</span></a></h3><p>动态导入常用在router中 在router中导入的组件使用动态导入，对应路由的组件会被编译但不会被加载，当跳转该路由时，对应的组件才会加载 动态导入语法使用的<code>import</code>语法返回的是一个<code>promise</code>对象，在es6才支持的 webpack中的动态导入在es6之前就支持是因为webpack借鉴commonjs规范写的一个导入函数，返回的也是一个<code>promise</code>对象</p><h3 id="cdn加速" tabindex="-1"><a class="header-anchor" href="#cdn加速"><span>cdn加速</span></a></h3><p>cdn（content delivery network）内容分发网络</p><p>在远距离传输的情况下，如：跨国访问网站。由于物理距离的原因访问速度都比较慢 将依赖的第三方模块全部写成cdn的形式，保证项目逻辑代码的小体积（体积小服务器和客户端的传输压力就没那么大） 使用cdn的方式导入第三方库，用户在访问时会自动去距离最近的cdn库所在服务器请求</p><p>在vite中使用<code>vite-plugin-cdn-import</code>插件进行cdn导入</p><ul><li>name：导入的包名</li><li>var：在项目中导入包的别名</li><li>path：cdn url</li></ul><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>plugins:[</span></span>
<span class="line"><span>	viteCDNPlugin({</span></span>
<span class="line"><span>		modules:[</span></span>
<span class="line"><span>			{</span></span>
<span class="line"><span>				name:&quot;lodash&quot;,</span></span>
<span class="line"><span>				var:&quot;_&quot;,</span></span>
<span class="line"><span>				path:&quot;https://cdn.jsdelivery.net/npm/lodasH@4.17.21/lodash.min.js&quot;</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		]</span></span>
<span class="line"><span>	})</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在vite中配置后无需改动项目代码使用es6的导入语法，vite会将已配置的cdn导入的包使用cdn导入</p><p>在webpack中直接使用script标签cdn导入</p><h3 id="跨域" tabindex="-1"><a class="header-anchor" href="#跨域"><span>跨域</span></a></h3><p>同源策略【仅在浏览器发生，是浏览器的规则】：http交互默认情况下只能在同协议同域名同端口的两台终端进行 跨域限制是服务器已经响应了东西，但是浏览器不给你，不是说服务器没响应东西 当网络请求时浏览器不知道是否是跨域访问，但都放行了，如果不是跨域请求的话响应都会正常返回，如果是跨域请求，请求的服务器相应来的数据如果是在白名单上的地址则会给出标记，浏览器看到标记也会放行，但如果不是白名单上的地址就不会给出标记，如果运行访问依旧会给出数据，但这个数据会被浏览器拦截</p><h4 id="开发服务器解决跨域问题" tabindex="-1"><a class="header-anchor" href="#开发服务器解决跨域问题"><span>开发服务器解决跨域问题</span></a></h4><p><strong>中转服务器</strong> 同源策略是浏览器的，让请求的地址指向本机服务器，再由本机服务器根据接口的映射向获取数据的服务器发送请求，获取到数据后本机服务器直接返回给网页</p><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default viteConfig({</span></span>
<span class="line"><span>	server:{    //开发服务器中的配置</span></span>
<span class="line"><span>		proxy:{    //配置跨域解决方案</span></span>
<span class="line"><span>			&quot;/api&quot;:{</span><span>    // key + 描述对象 以后在遇到/api开头的请求时 都将其代理到 target属性对应的域中去</span></span>
<span class="line"><span>				target:&quot;https://www.360.com&quot;,</span></span>
<span class="line"><span>				changeOrigin: true,</span></span>
<span class="line"><span>				rewrite：(path)=&gt; path.replace（/^\\/api/，），//·是否要重写api路径</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="生产时态" tabindex="-1"><a class="header-anchor" href="#生产时态"><span>生产时态</span></a></h4><p>一般是交给后端去处理跨域的【后端或者运维做的】：</p><ol><li>ngnix：代理服务本质的原理就是和我们的本地开发vite服务器做跨域是一样</li><li>配置身份标记：Access-Control-Allow-Origin：代表哪些域是我的朋友，标记了朋友以后浏览器就不会拦截</li></ol><blockquote><p>[!Title] Title public下的包是不会做任何优化的</p></blockquote>`,101)]))}const r=a(p,[["render",d]]),o=JSON.parse('{"path":"/front/engineering/3/","title":"3 vite","lang":"zh-CN","frontmatter":{"title":"3 vite","createTime":"2025/04/13 13:38:28","permalink":"/front/engineering/3/"},"readingTime":{"minutes":17.86,"words":5357},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/工程化/3 vite.md","headers":[]}');export{r as comp,o as data};
